// Auto-generated by Codename One from the com.codename1.surfaces framework.
// Compiled ONLY into the CN1Widgets extension target (iOS 16.1+), so no availability
// guards are needed here. Tolerant, Codable-free parsing of the canonical surfaces wire
// format (schema v1) produced by com.codename1.surfaces.SurfaceSerializer: unknown keys
// are ignored, missing optionals degrade to sensible defaults.

import Foundation
import SwiftUI
import UIKit

// MARK: - Typed accessors over JSONSerialization output

func cn1Str(_ dict: [String: Any], _ key: String) -> String? {
    return dict[key] as? String
}

func cn1Dict(_ dict: [String: Any], _ key: String) -> [String: Any]? {
    return dict[key] as? [String: Any]
}

func cn1Arr(_ dict: [String: Any], _ key: String) -> [Any]? {
    return dict[key] as? [Any]
}

/// Numbers arrive as NSNumber (Int/Double/Bool are all bridged) or, defensively, strings.
func cn1Double(_ value: Any?) -> Double? {
    if let n = value as? NSNumber {
        return n.doubleValue
    }
    if let s = value as? String {
        return Double(s)
    }
    return nil
}

func cn1Int(_ value: Any?) -> Int? {
    if let n = value as? NSNumber {
        return n.intValue
    }
    if let s = value as? String {
        return Int(s)
    }
    return nil
}

func cn1CGFloat(_ value: Any?) -> CGFloat? {
    if let d = cn1Double(value) {
        return CGFloat(d)
    }
    return nil
}

func cn1Bool(_ value: Any?) -> Bool {
    if let n = value as? NSNumber {
        return n.boolValue
    }
    if let s = value as? String {
        return s == "true"
    }
    return false
}

/// Epoch-milliseconds value (the wire format for all dates) to Date.
func cn1DateMs(_ value: Any?) -> Date? {
    guard let ms = cn1Double(value) else {
        return nil
    }
    return Date(timeIntervalSince1970: ms / 1000.0)
}

func cn1ParseJSONObject(_ json: String?) -> [String: Any] {
    guard let json = json, let data = json.data(using: .utf8) else {
        return [:]
    }
    let parsed = try? JSONSerialization.jsonObject(with: data, options: [])
    return parsed as? [String: Any] ?? [:]
}

func cn1LoadJSONObject(_ url: URL) -> [String: Any]? {
    guard let data = try? Data(contentsOf: url) else {
        return nil
    }
    let parsed = try? JSONSerialization.jsonObject(with: data, options: [])
    return parsed as? [String: Any]
}

// MARK: - State interpolation

/// Replaces ${key} placeholders with the matching state value; unknown keys resolve to "".
func cn1Interpolate(_ template: String, state: [String: Any]) -> String {
    guard template.contains("${") else {
        return template
    }
    var out = ""
    var rest = Substring(template)
    while let start = rest.range(of: "${") {
        out += rest[..<start.lowerBound]
        let afterStart = rest[start.upperBound...]
        guard let end = afterStart.range(of: "}") else {
            out += rest[start.lowerBound...]
            return out
        }
        let key = String(afterStart[..<end.lowerBound])
        if let value = state[key] {
            if let s = value as? String {
                out += s
            } else if let n = value as? NSNumber {
                // Render integral numbers without a trailing ".0".
                if n.doubleValue == n.doubleValue.rounded() && abs(n.doubleValue) < 1e15 {
                    out += String(n.int64Value)
                } else {
                    out += n.stringValue
                }
            } else {
                out += String(describing: value)
            }
        }
        rest = afterStart[end.upperBound...]
    }
    out += rest
    return out
}

// MARK: - Colors

/// Converts a signed 32-bit ARGB int (the wire format for colors) to UIColor.
func cn1UIColor(argb: Int) -> UIColor {
    let v = UInt32(bitPattern: Int32(truncatingIfNeeded: argb))
    let a = CGFloat((v >> 24) & 0xff) / 255.0
    let r = CGFloat((v >> 16) & 0xff) / 255.0
    let g = CGFloat((v >> 8) & 0xff) / 255.0
    let b = CGFloat(v & 0xff) / 255.0
    return UIColor(red: r, green: g, blue: b, alpha: a)
}

/// Color spec: {"l": argb, "d": argb} (light/dark pair, resolved via trait collection)
/// or {"role": "label|secondaryLabel|background|accent"} (semantic role).
func cn1Color(_ spec: Any?) -> Color? {
    guard let dict = spec as? [String: Any] else {
        return nil
    }
    if let role = dict["role"] as? String {
        switch role {
        case "label":
            return Color.primary
        case "secondaryLabel":
            return Color.secondary
        case "background":
            return Color(UIColor.systemBackground)
        case "accent":
            return Color.accentColor
        default:
            return nil
        }
    }
    guard let light = cn1Int(dict["l"]) else {
        return nil
    }
    let dark = cn1Int(dict["d"]) ?? light
    return Color(UIColor { trait in
        trait.userInterfaceStyle == .dark ? cn1UIColor(argb: dark) : cn1UIColor(argb: light)
    })
}

// MARK: - Vector node parsing

/// Coordinate-pair list of a vector path op ("pts": [x0, y0, x1, y1, ...]).
func cn1PointList(_ value: Any?) -> [CGPoint] {
    guard let arr = value as? [Any] else {
        return []
    }
    var out: [CGPoint] = []
    var i = 0
    while i + 1 < arr.count {
        if let x = cn1CGFloat(arr[i]), let y = cn1CGFloat(arr[i + 1]) {
            out.append(CGPoint(x: x, y: y))
        }
        i += 2
    }
    return out
}

/// Converts a clock-convention angle (the surfaces wire convention: degrees, 0 = 12 o'clock,
/// clockwise positive) to a SwiftUI Angle. Path angles measure from 3 o'clock advancing
/// clockwise in SwiftUI's y-down coordinate space, so the conversion subtracts 90 degrees.
func cn1ClockAngle(_ clockDegrees: CGFloat) -> Angle {
    return .degrees(Double(clockDegrees) - 90)
}

// MARK: - Fonts and alignment

func cn1FontWeight(_ value: Any?) -> Font.Weight {
    switch value as? String {
    case "light":
        return .light
    case "medium":
        return .medium
    case "semibold":
        return .semibold
    case "bold":
        return .bold
    default:
        return .regular
    }
}

func cn1Alignment(_ value: Any?) -> Alignment? {
    switch value as? String {
    case "topLeading":
        return .topLeading
    case "top":
        return .top
    case "topTrailing":
        return .topTrailing
    case "leading":
        return .leading
    case "center":
        return .center
    case "trailing":
        return .trailing
    case "bottomLeading":
        return .bottomLeading
    case "bottom":
        return .bottom
    case "bottomTrailing":
        return .bottomTrailing
    default:
        return nil
    }
}

// MARK: - Actions

/// Builds the canonical surfaces deep link cn1surface://a?src=..&id=..&p=<url-encoded JSON>
/// handled by the Codename One app delegate.
func cn1ActionURL(source: String, action: [String: Any]) -> URL? {
    guard let actionId = action["id"] as? String else {
        return nil
    }
    var components = URLComponents()
    components.scheme = "cn1surface"
    components.host = "a"
    var items = [URLQueryItem(name: "src", value: source), URLQueryItem(name: "id", value: actionId)]
    if let params = action["p"], JSONSerialization.isValidJSONObject(params),
       let data = try? JSONSerialization.data(withJSONObject: params, options: []),
       let json = String(data: data, encoding: .utf8) {
        items.append(URLQueryItem(name: "p", value: json))
    }
    components.queryItems = items
    return components.url
}

// MARK: - Shared container locations

/// Root of the App Group container, resolved from the generated cn1SurfacesAppGroup constant.
func cn1SurfacesContainerURL() -> URL? {
    return FileManager.default.containerURL(forSecurityApplicationGroupIdentifier: cn1SurfacesAppGroup)
}

/// Directory holding one widget kind's published timeline.json + image blobs.
func cn1SurfacesKindDir(_ kind: String) -> URL? {
    return cn1SurfacesContainerURL()?
        .appendingPathComponent("cn1surfaces", isDirectory: true)
        .appendingPathComponent(kind, isDirectory: true)
}

/// Directory holding image blobs referenced by live activity descriptors.
func cn1SurfacesActivitiesDir() -> URL? {
    return cn1SurfacesContainerURL()?
        .appendingPathComponent("cn1surfaces", isDirectory: true)
        .appendingPathComponent("activities", isDirectory: true)
}

// MARK: - Timeline document

struct CN1TimelineEntry {
    let date: Date
    let state: [String: Any]
}

struct CN1Timeline {
    let kind: String
    let reloadAtEnd: Bool
    let layouts: [String: Any]
    let entries: [CN1TimelineEntry]

    /// Parses a timeline.json document; returns nil when the document is unusable.
    static func parse(_ doc: [String: Any]) -> CN1Timeline? {
        guard let layouts = cn1Dict(doc, "layouts"), !layouts.isEmpty else {
            return nil
        }
        var entries: [CN1TimelineEntry] = []
        for rawEntry in cn1Arr(doc, "entries") ?? [] {
            guard let entryDict = rawEntry as? [String: Any], let date = cn1DateMs(entryDict["date"]) else {
                continue
            }
            entries.append(CN1TimelineEntry(date: date, state: cn1Dict(entryDict, "state") ?? [:]))
        }
        if entries.isEmpty {
            entries.append(CN1TimelineEntry(date: Date(), state: [:]))
        }
        entries.sort { $0.date < $1.date }
        return CN1Timeline(
                kind: cn1Str(doc, "kind") ?? "",
                reloadAtEnd: (cn1Str(doc, "reload") ?? "atEnd") != "never",
                layouts: layouts,
                entries: entries)
    }

    static func load(kind: String) -> CN1Timeline? {
        guard let dir = cn1SurfacesKindDir(kind),
              let doc = cn1LoadJSONObject(dir.appendingPathComponent("timeline.json")) else {
            return nil
        }
        return parse(doc)
    }

    /// The entry that should be visible now: the latest entry whose date has passed,
    /// or the first entry when they are all in the future.
    func currentEntry(at now: Date = Date()) -> CN1TimelineEntry {
        var current = entries[0]
        for entry in entries where entry.date <= now {
            current = entry
        }
        return current
    }
}
